<?php
namespace Database\Factories;use App\Domain\Inventory\Instances\ItemInstanceOriginType;use App\Domain\Inventory\Instances\ItemInstanceStatus;use App\Models\Character;use App\Models\Item;use App\Models\ItemInstance;use Illuminate\Database\Eloquent\Factories\Factory;
class ItemInstanceFactory extends Factory{protected $model=ItemInstance::class;public function definition(){return['uuid'=>$this->faker->unique()->uuid,'character_id'=>Character::factory(),'item_id'=>function(){return Item::create(['code'=>'instance-'.$this->faker->unique()->numerify('########'),'name'=>$this->faker->word,'item_type'=>'equipment','equipment_type'=>'weapon','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active'])->id;},'refinement_level'=>0,'status'=>ItemInstanceStatus::AVAILABLE,'origin_type'=>ItemInstanceOriginType::LEGACY_INVENTORY,'origin_id'=>$this->faker->unique()->numberBetween(1,PHP_INT_MAX),'origin_unit_index'=>1,'acquired_at'=>now()];}public function equipped(){return$this->state(function(){return['status'=>ItemInstanceStatus::EQUIPPED];});}public function sold(){return$this->state(function(){return['status'=>ItemInstanceStatus::SOLD];});}}
